sql:
SELECT machine_architecture 
FROM executables 
WHERE size > 10000000;

SELECT os_type, COUNT(*) 
FROM executables 
GROUP BY os_type;

SELECT * 
FROM executables 
ORDER BY exec_id;

SELECT file_type, size_of_image, entropy
FROM executables
ORDER BY entropy DESC;

SELECT template_id, template_name
FROM report_templates
WHERE template_data LIKE '%template%';

SELECT COUNT(*)
FROM executables
WHERE exec_id NOT IN (
  SELECT exec_id
  FROM imported_dlls
);

SELECT AVG(size) 
FROM executables 
WHERE exec_id IN (SELECT DISTINCT exec_id FROM access_logs);

SELECT dll_name 
FROM imported_dlls
WHERE exec_id = 1;

SELECT COUNT(DISTINCT exec_id)
FROM analysis_results
WHERE analysis_type = 'malware scan';

SELECT DISTINCT dll_name
FROM imported_dlls
ORDER BY dll_name ASC;
